<?php namespace App\Http\Controllers\Auth; use App\Http\Controllers\Controller; use App\Http\Requests\Auth\LoginRequest; use App\Services\Auth\AuthService; use Illuminate\Http\JsonResponse; class AuthController extends Controller { public function __construct(private AuthService $authService) {} public function login(LoginRequest $req): JsonResponse { $result = $this->authService->login($req->email, $req->password, $req->latitude, $req->longitude, $req->deviceFingerprint, $req->userAgent); return response()->json($result); } public function me(): JsonResponse { return response()->json(auth()->user()); } }
